import React, {useState, useEffect} from 'react';
import "../../styles/Main.scss"
import Messages from "./Messages/messages";
import SideBar from "./SideBar/sidebar";
import * as signalR from "@microsoft/signalr";
import {useDispatch, useSelector} from "react-redux";
import {getSideBarStatus} from "../../store/reducers/appSelector";
import {SetChatsConnectionActionCreator} from "../../store/reducers/appReducer";
import {
    SetChatsListActionCreator,
    SetCurrentChatActionCreator,
    UpdateChatsActionCreator
} from "../../store/reducers/chatsReducer";
import {getChatsList} from "../../store/reducers/chatsSelector";


const Main = () => {
    const dispatch = useDispatch();
    const SideBarStatus = useSelector(getSideBarStatus);
    const ChatsList = useSelector(getChatsList)
    const [messages, setMessages] = useState([]);

    //SignalR socket connection
    useEffect(() => {
        let currentConnection;
        if (localStorage.AUTH_TOKEN) {
            (async () => {
                const newConnection = new signalR.HubConnectionBuilder()
                    .withUrl('/hubs/chat', {
                        accessTokenFactory: () => localStorage.AUTH_TOKEN.split(" ")[1]
                    }) // Ensure same as BE
                    .configureLogging(signalR.LogLevel.Information)
                    .withAutomaticReconnect([1000, 3000, 5000, null])
                    .build();
                newConnection.on('GetChats', (data) => {
                    console.log(data)
                    dispatch(SetChatsListActionCreator(data))
                });
                newConnection.on('UpdateChat', (data) => {
                    dispatch(UpdateChatsActionCreator(data))
                    console.log(data)
                });
                newConnection.on('GetMessage', (data) => {
                    console.log(data)
                    setMessages(messages => [...messages, data]);
                });
                newConnection.on('GetMessages', (data) => {
                    console.log(data)
                    setMessages(data);
                });

                await newConnection.start();
                currentConnection = newConnection;
                dispatch(SetChatsConnectionActionCreator(newConnection));
            })();
            return async () => {
                await currentConnection.stop()
                dispatch(SetCurrentChatActionCreator(null))
            }
        }
    }, [])
    // SignalR socket connection

    return (
        <div className={SideBarStatus ? "Main active" : "Main"}>
            <SideBar chats={ChatsList}/>
            <Messages messages={messages} setMessages={setMessages}/>
        </div>
    );
};

export default Main;